public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    protected readonly DbContext _dbContext;
    protected readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
        _dbSet = _dbContext.Set<T>();
    }

    public virtual async Task<T> GetByIdAsync(int id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync()
    {
        return await _dbSet.ToListAsync();
    }

    public virtual async Task<T> GetByDynamicFieldAsync(string fieldName, object value)
    {
        return await _dbSet
            .Where(x => x.GetType().GetProperty(fieldName).GetValue(x).Equals(value))
            .FirstOrDefaultAsync();
    }

    public virtual async Task<IEnumerable<T>> GetByDynamicFieldAsync(string fieldName, object value, int skip, int take)
    {
        return await _dbSet
            .Where(x => x.GetType().GetProperty(fieldName).GetValue(x).Equals(value))
            .Skip(skip)
            .Take

